import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from "@/lib/db";
import { PUBLIC_CATEGORIES } from "@/lib/public-data";

const createListingSchema = z.object({
  title: z.string().min(1, "Назва обов'язкова").max(200),
  description: z.string().min(1, "Опис обов'язковий").max(5000),
  images: z.array(z.string()).optional().default([]),
  categoryId: z.string().uuid("Некоректна категорія"),
  sellerId: z.string().uuid("Некоректний продавець"),
  type: z.enum(["AUCTION", "BUY_NOW", "HYBRID"]),
  startPrice: z.number().positive("Стартова ціна має бути > 0"),
  buyNowPrice: z.number().positive().optional().nullable(),
  bidStep: z.number().positive("Крок ставки має бути > 0").optional().default(50),
  endDate: z.string().min(1, "Дата завершення обов'язкова"),
  deliveryOptions: z.array(z.string()).optional().default([]),
});

function formatListing(l: Record<string, unknown> & { id: string; title: string; images: string; deliveryOptions: string; endDate: Date | string; createdAt: Date | string; bidsCount?: number; _count?: { bids: number } }) {
  let images: string[] = [];
  let deliveryOptions: string[] = [];
  try { images = Array.isArray(l.images) ? l.images : JSON.parse(l.images); } catch { images = [l.images].filter(Boolean); }
  try { deliveryOptions = Array.isArray(l.deliveryOptions) ? l.deliveryOptions : JSON.parse(l.deliveryOptions); } catch { deliveryOptions = []; }
  return {
    ...l,
    images,
    deliveryOptions,
    bidsCount: l.bidsCount ?? l._count?.bids ?? 0,
    endDate: typeof l.endDate === "string" ? l.endDate : l.endDate?.toISOString?.(),
    createdAt: typeof l.createdAt === "string" ? l.createdAt : l.createdAt?.toISOString?.(),
  };
}

async function ensurePublicCategories() {
  await Promise.all(
    PUBLIC_CATEGORIES.map((c) =>
      prisma.category.upsert({
        where: { slug: c.slug },
        update: { name: c.name, icon: c.icon },
        create: c,
      })
    )
  );
}

export async function GET(req: NextRequest) {
  const { searchParams } = new URL(req.url);
  const categoryId = searchParams.get("categoryId");
  const sellerId = searchParams.get("sellerId");

  try {
    const where: Record<string, string> = {};
    if (categoryId) where.categoryId = categoryId;
    if (sellerId) where.sellerId = sellerId;

    await ensurePublicCategories();

    const listings = await prisma.listing.findMany({
      where,
      include: { _count: { select: { bids: true } } },
      orderBy: { createdAt: "desc" },
    });
    const categories = await prisma.category.findMany();
    return NextResponse.json({ listings: listings.map(formatListing), categories: categories.length ? categories : PUBLIC_CATEGORIES });
  } catch (error) {
    console.warn("Listings DB unavailable; returning empty real marketplace state:", error);
    return NextResponse.json({ listings: [], categories: PUBLIC_CATEGORIES, source: "empty-no-database" });
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const parsed = createListingSchema.parse(body);

    const newListing = await prisma.listing.create({
      data: {
        title: parsed.title,
        description: parsed.description,
        images: JSON.stringify(parsed.images),
        categoryId: parsed.categoryId,
        sellerId: parsed.sellerId,
        type: parsed.type,
        startPrice: parsed.startPrice,
        currentPrice: parsed.startPrice,
        buyNowPrice: parsed.buyNowPrice ?? null,
        bidStep: parsed.bidStep,
        endDate: new Date(parsed.endDate),
        deliveryOptions: JSON.stringify(parsed.deliveryOptions),
        status: "ACTIVE",
      },
    });
    return NextResponse.json({ success: true, listing: formatListing(newListing) });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.errors[0].message }, { status: 400 });
    }
    return NextResponse.json({ error: "Внутрішня помилка сервера" }, { status: 500 });
  }
}
